+                Ok(n) => return Ok(n),
+                Err(ref e) if e.kind() == io::ErrorKind::WouldBlock => {
+                    // TODO: Replace with proper reactor wait when integration is complete
+                    crate::runtime::yield_now().await;
+                }
+                Err(e) => return Err(e),
